import anthropic, statistics, json
from datetime import datetime, timedelta, timezone

_client = anthropic.Anthropic()

def dispatch_alert(tier: int, control_id: str, details: dict) -> None:
    """Route a detective-control finding to the correct escalation tier."""
    payload = {
        "tier": tier,
        "control_id": control_id,
        "details": details,
        "ts": datetime.now(timezone.utc).isoformat(),
    }
    if tier == 1:
        _write_to_dashboard(payload)          # low-priority queue
    elif tier == 2:
        _page_on_call(payload)                # PagerDuty / Opsgenie
    else:
        _declare_incident(payload)            # incident management + legal notification

def _write_to_dashboard(p): print(f"[DASHBOARD] {json.dumps(p)}")
def _page_on_call(p):       print(f"[ONCALL]    {json.dumps(p)}")
def _declare_incident(p):   print(f"[INCIDENT]  {json.dumps(p)}")

# Integrate with the token anomaly detector from the previous section
def monitored_claude_call(user_id: str, messages: list, baseline: list[float]) -> str:
    response = _client.messages.create(
        model="claude-opus-4-8",
        max_tokens=2048,
        messages=messages,
    )
    tokens = response.usage.output_tokens
    mu = statistics.mean(baseline) if baseline else tokens
    sigma = statistics.stdev(baseline) if len(baseline) > 1 else 1
    z = (tokens - mu) / sigma
    if z > 3.5:
        dispatch_alert(3, "TOK-001", {"z_score": round(z, 2), "tokens": tokens, "user_id": user_id})
    elif z > 2.5:
        dispatch_alert(2, "TOK-001", {"z_score": round(z, 2), "tokens": tokens, "user_id": user_id})
    elif z > 1.5:
        dispatch_alert(1, "TOK-001", {"z_score": round(z, 2), "tokens": tokens, "user_id": user_id})
    return response.content[0].text
